UPDATE workflow_entity SET "nodes"='[{"parameters": {"httpMethod": "POST", "path": "ia360-whatsapp-handoff", "responseMode": "responseNode", "options": {}}, "id": "Webhook_IA360_Handoff", "name": "Webhook IA360 Handoff", "type": "n8n-nodes-base.webhook", "typeVersion": 2, "position": [-620, 0]}, {"parameters": {"mode": "runOnceForAllItems", "jsCode": "\nconst payload = $input.first().json.body || $input.first().json;\nfunction cleanDigits(v) { return String(v || '''').replace(/\\D/g, ''''); }\nfunction required(v, name) { if (!v) throw new Error(`Missing ${name}`); return v; }\nfunction mapEspoStage(eventType, targetStage) {\n  if (eventType === ''proposal_requested'' || targetStage === ''Propuesta / siguiente paso'') return ''Proposal'';\n  if (eventType === ''opt_out'') return ''Closed Lost'';\n  // Current EspoCRM install only exposes Prospecting, Qualification, Proposal,\n  // Negotiation, Closed Won, Closed Lost. Until custom stages exist, confirmed\n  // meetings stay Qualification, while ForgeChat carries the precise\n  // Reunión agendada conversational state.\n  if (eventType === ''meeting_confirmed_calendar_zoom'') return ''Qualification'';\n  if (eventType === ''agenda_preference_selected'' || eventType === ''call_requested'') return ''Qualification'';\n  if (eventType === ''map_requested'' || eventType === ''flow_map_requested'' || eventType === ''example_requested'' || eventType === ''mechanism_selected'' || eventType === ''pain_segmented'') return ''Qualification'';\n  if (eventType === ''nurture_selected'') return null;\n  return targetStage ? ''Qualification'' : ''Prospecting'';\n}\nfunction shouldCreateTask(eventType, priority) {\n  return priority === ''high'' || [\n    ''apply_requested'', ''scope_requested'', ''proposal_requested'', ''call_requested'',\n    ''agenda_preference_selected'', ''meeting_confirmed_calendar_zoom'', ''diagnostic_answered''\n  ].includes(eventType);\n}\nfunction recommendedOffer(eventType, targetStage, summary) {\n  const text = `${eventType || ''''} ${targetStage || ''''} ${summary || ''''}`.toLowerCase();\n  if (text.includes(''erp'') || text.includes(''bi'') || text.includes(''datapower'') || text.includes(''reporte'')) return ''DataPower BI / ERP analytics'';\n  if (text.includes(''whatsapp'') || text.includes(''crm'')) return ''WhatsApp Revenue OS / CRM conversacional'';\n  if (text.includes(''agent'') || text.includes(''follow'')) return ''Agentic Follow-up'';\n  if (text.includes(''gobierno'')) return ''Gobierno IA'';\n  if (eventType === ''meeting_confirmed_calendar_zoom'' || eventType === ''call_requested'') return ''Discovery IA360'';\n  return ''Diagnóstico IA360 / Mapa 30-60-90'';\n}\nconst espoBase = required($env.ESPOCRM_URL, ''ESPOCRM_URL'').replace(/\\/$/, '''') + ''/api/v1'';\nconst espoUser = required($env.ESPOCRM_ADMIN_USERNAME, ''ESPOCRM_ADMIN_USERNAME'');\nconst espoPass = required($env.ESPOCRM_ADMIN_PASSWORD, ''ESPOCRM_ADMIN_PASSWORD'');\nconst auth = ''Basic '' + Buffer.from(`${espoUser}:${espoPass}`).toString(''base64'');\nasync function espo(method, path, body) {\n  const opts = { method, url: espoBase + path, headers: { Authorization: auth, ''Content-Type'': ''application/json'' }, json: true };\n  if (body) opts.body = body;\n  try {\n    return await this.helpers.httpRequest(opts);\n  } catch (e) {\n    throw new Error(`Espo ${method} ${path} failed: ${e.message}`);\n  }\n}\nasync function findByName(entity, name) {\n  const qs = ''where%5B0%5D%5Btype%5D=equals'' + ''&where%5B0%5D%5Battribute%5D=name'' + ''&where%5B0%5D%5Bvalue%5D='' + encodeURIComponent(name) + ''&maxSize=1'';\n  const data = await espo.call(this, ''GET'', `/${entity}?${qs}`);\n  return (data.list || [])[0] || null;\n}\nasync function upsertByName(entity, name, body) {\n  const existing = await findByName.call(this, entity, name);\n  if (existing && existing.id) {\n    const updated = await espo.call(this, ''PUT'', `/${entity}/${existing.id}`, body);\n    return { action: ''updated'', record: updated };\n  }\n  const created = await espo.call(this, ''POST'', `/${entity}`, body);\n  return { action: ''created'', record: created };\n}\nif (payload.source !== ''forgechat-ia360-webhook'') throw new Error(''Invalid source'');\nconst contact = payload.contact || {};\nconst trigger = payload.trigger || {};\nconst wa = cleanDigits(contact.contactNumber);\nif (!wa) throw new Error(''Missing contact.contactNumber'');\nconst displayName = contact.contactName || `WhatsApp ${wa}`;\nconst eventType = payload.eventType || ''ia360_handoff'';\nconst targetStage = payload.targetStage || ''Agenda en proceso'';\nconst priorityRaw = payload.priority || ''normal'';\nconst priority = priorityRaw === ''high'' ? ''High'' : ''Normal'';\nconst summary = payload.summary || '''';\nconst espoStage = mapEspoStage(eventType, targetStage);\nconst createTask = shouldCreateTask(eventType, priorityRaw);\nconst offer = recommendedOffer(eventType, targetStage, summary);\nconst marker = ''[ForgeChat IA360 n8n Sync]'';\nconst accountName = ''ForgeChat IA360 WhatsApp'';\nconst contactName = `${displayName} WhatsApp IA360`;\nconst opportunityName = `IA360 WhatsApp - ${displayName}`;\nconst taskName = `IA360 WhatsApp handoff - ${displayName}`;\nconst descriptionBase = `${marker}\\nEvento: ${eventType}\\nPrioridad: ${priorityRaw}\\nStage ForgeChat: ${targetStage}\\nStage Espo recomendado: ${espoStage || ''N/A''}\\nOferta sugerida: ${offer}\\nContacto WA: +${wa}\\nNombre: ${displayName}\\nÚltima respuesta: ${trigger.messageBody || ''''}\\nResumen: ${summary}\\nOcurrió: ${payload.occurredAt || new Date().toISOString()}\\nAcciones recomendadas: ${(payload.recommendedActions || []).join('', '')}`;\nconst appUser = await espo.call(this, ''GET'', ''/App/user'');\nconst currentUser = appUser.user || appUser;\nconst assignedUserId = currentUser.id;\nconst assignedUserName = currentUser.name || currentUser.userName || ''Admin'';\nconst accountRes = await upsertByName.call(this, ''Account'', accountName, { name: accountName, type: ''Customer'', assignedUserId, assignedUserName, description: `${marker}\\nCuenta puente para handoffs IA360 generados desde ForgeChat WhatsApp. Último WA: +${wa}.` });\nconst parts = displayName.split(/\\s+/);\nconst firstName = parts.slice(0, -1).join('' '') || displayName;\nconst lastName = parts.length > 1 ? `${parts[parts.length - 1]} WhatsApp IA360` : ''WhatsApp IA360'';\nconst contactRes = await upsertByName.call(this, ''Contact'', contactName, { firstName, lastName, assignedUserId, assignedUserName, description: descriptionBase + ''\\n\\nNota: WA se guarda en descripción para evitar rechazo por validación estricta de phoneNumber en EspoCRM.'' });\nlet opportunityRes = null;\nif (espoStage) {\n  const closeDate = new Date(Date.now() + 14 * 86400000).toISOString().slice(0, 10);\n  opportunityRes = await upsertByName.call(this, ''Opportunity'', opportunityName, { name: opportunityName, stage: espoStage, amount: 0, closeDate, assignedUserId, assignedUserName, description: descriptionBase });\n}\nlet taskRes = null;\nif (createTask) {\n  const due = new Date(Date.now() + (priority === ''High'' ? 2 : 24) * 3600000).toISOString().slice(0, 19).replace(''T'', '' '');\n  const nextAction = eventType === ''meeting_confirmed_calendar_zoom''\n    ? ''Preparar briefing humano para reunión confirmada; Calendar/Zoom ya existen.''\n    : eventType === ''call_requested'' || eventType === ''agenda_preference_selected''\n      ? ''Revisar contexto en ForgeChat y confirmar horario real; no contar como reunión confirmada hasta crear evento.''\n      : eventType === ''proposal_requested''\n        ? ''Preparar alcance/costo con base en contexto y oferta sugerida.''\n        : ''Revisar contexto y definir siguiente acción humana.'';\n  taskRes = await upsertByName.call(this, ''Task'', taskName, { name: taskName, status: ''Not Started'', priority, dateEnd: due, assignedUserId, assignedUserName, description: descriptionBase + `\\n\\nSiguiente acción humana: ${nextAction}` });\n}\nreturn [{ json: { ok: true, source: ''n8n-ia360-handoff-code-httpRequest'', eventType, wa, mapping: { targetStage, espoStage, createTask, offer }, espocrm: { account: { action: accountRes.action, id: accountRes.record.id, name: accountRes.record.name }, contact: { action: contactRes.action, id: contactRes.record.id, name: contactRes.record.name }, opportunity: opportunityRes ? { action: opportunityRes.action, id: opportunityRes.record.id, name: opportunityRes.record.name, stage: opportunityRes.record.stage } : null, task: taskRes ? { action: taskRes.action, id: taskRes.record.id, name: taskRes.record.name, priority: taskRes.record.priority, status: taskRes.record.status } : null } } }];\n"}, "id": "Code_EspoCRM_Sync", "name": "Code EspoCRM Sync", "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [-300, 0]}, {"parameters": {"respondWith": "json", "responseBody": "={{ $json }}", "options": {}}, "id": "Respond_OK", "name": "Respond OK", "type": "n8n-nodes-base.respondToWebhook", "typeVersion": 1.1, "position": [20, 0]}]'::json, "connections"='{"Webhook IA360 Handoff": {"main": [[{"node": "Code EspoCRM Sync", "type": "main", "index": 0}]]}, "Code EspoCRM Sync": {"main": [[{"node": "Respond OK", "type": "main", "index": 0}]]}}'::json, "settings"='{"executionOrder": "v1"}'::json, "staticData"=NULL, "pinData"='{}'::json, "meta"='{"templateCredsSetupCompleted": true}'::json, "nodeGroups"='[]'::json, "updatedAt"=now(), "versionCounter"="versionCounter"+1 WHERE id='IA360WhatsAppHandoffDraft20260601';
SELECT id,name,active,"versionCounter" FROM workflow_entity WHERE id='IA360WhatsAppHandoffDraft20260601';
